// Embeddable AgenC marketplace SDK.
// generated/ = Codama @solana/kit client + event codecs (AUTOGENERATED, do not edit).
// facade/    = hand-written ergonomic instruction builders.
// client/    = transaction runtime (createMarketplaceClient, AgencError, Transport).
// queries/   = typed getProgramAccounts read path (indexer-swappable transport).
// indexer/   = hosted indexer API client (the scale read path + tx builder).
// webhooks/  = webhook delivery signature verification.
// events/    = log parsing, subscriptions, waitForTaskStatus.
// watch/     = watchClaimableTasks (worker-notification convenience over events+queries).
// values/    = ids, hashing, listing-metadata codecs, canonical job-spec hash.
// taskThread/= P7.1 buyer<->worker message envelopes (content-addressed comms).
// delivery/  = P7.2 encrypted deliverable handoff (fair exchange, WebCrypto).
export * from "./generated/index.js";
export * as facade from "./facade/index.js";
export * from "./client/index.js";
export * from "./queries/index.js";
export * from "./indexer/index.js";
export * from "./webhooks/index.js";
export * from "./events/index.js";
export * from "./watch/index.js";
export * as values from "./values/index.js";

// P7.1 / P7.2 off-chain content rails. Namespaced (like `values`/`facade`) so
// generic helper names (`encryptDeliverable`, `postTaskMessage`,
// `createContentTransport`) don't collide with the flat top-level surface.
export * as taskThread from "./task-thread/index.js";
export * as delivery from "./delivery/index.js";

// The P3.4 public moderation helper lives next to the devnet sandbox helpers
// in src/sandbox/ but is NOT devnet-only: it POSTs a job spec to the
// configured moderation endpoint (the environment seam, which includes a
// production hosted endpoint) and holds no key, sends no funds, and
// broadcasts nothing. Re-export it from the package root — alongside
// createIndexerClient / verifyAgencWebhookSignature — so mainnet integrators
// reach it without importing through the "DEVNET ONLY" `/sandbox` subpath.
export {
  ListingModerationError,
  requestListingModeration,
  type ListingModerationAttestation,
  type ListingModerationResult,
  type ListingModerationVerdict,
  type RequestListingModerationInput,
} from "./sandbox/moderation.js";

// Every successful settlement has a shareable, independently verifiable
// receipt page — settle flows should surface this URL as the final line of
// the settlement handoff.
export { settlementReceiptUrl } from "./receipt.js";

// The complete buyer-side hire orchestration (hire → host/moderate job spec →
// activate) — the open-SDK home of the flow the react hook and the kit wrap.
export * from "./orchestration/index.js";

// P6.5 surface-versioning contract. `getDeployedSurface` is a top-level read
// capability (like getAgentTrackRecord) — re-export it and its types/error at the
// package root so mainnet integrators reach it without the `facade` namespace.
export {
  getDeployedSurface,
  capabilitiesForRevision,
  readSurfaceRevision,
  assertCapability,
  SurfaceNotDeployedError,
  SURFACE_REVISION_FULL,
  SURFACE_REVISION_OFFSET,
  OLD_PROTOCOL_CONFIG_SIZE,
  NEW_PROTOCOL_CONFIG_SIZE,
  type CapabilitySet,
} from "./facade/surface.js";
